function Get-Sha256([string]$f) {
  (Get-FileHash -LiteralPath $f -Algorithm SHA256).Hash.ToLower()
}
Write-Host "DRY RUN - files that would be removed:"
$targets = @()
foreach ($e in $files) {
  $full = [System.IO.Path]::GetFullPath($e.Path)
  if (-not $full.StartsWith($rootPrefix, [System.StringComparison]::OrdinalIgnoreCase)) {
    Write-Warning "outside managed root, skipping: $full"; continue
  }
  if (-not (Test-Path -LiteralPath $full)) { Write-Warning "already gone: $full"; continue }
  if ((Get-Sha256 $full) -ne $e.Sha) { Write-Warning "MODIFIED since copy, skipping: $full"; continue }
  Write-Host "  $full"
  $targets += $full
}
if ($targets.Count -eq 0) { Write-Host 'Nothing to remove.'; exit 0 }
$answer = Read-Host "Type YES to remove these $($targets.Count) file(s)"
if ($answer -ne 'YES') { Write-Host 'Aborted.'; exit 1 }
foreach ($t in $targets) { Remove-Item -LiteralPath $t -Force -Confirm:$false; Write-Host "removed $t" }
# remove now-empty program/category dirs (bottom-up), never the programs root's parent
$dirs = Get-ChildItem -LiteralPath $rootPrefix -Recurse -Directory | Sort-Object { $_.FullName.Length } -Descending
foreach ($d in $dirs) {
  if (-not (Get-ChildItem -LiteralPath $d.FullName -Force)) { Remove-Item -LiteralPath $d.FullName; Write-Host "removed empty dir $($d.FullName)" }
}
if (-not (Get-ChildItem -LiteralPath $rootPrefix -Force)) { Remove-Item -LiteralPath $rootPrefix; Write-Host "removed empty $rootPrefix" }
Write-Host 'Rollback complete. No pre-existing files were touched.'
